"use client";

import { toPng } from "html-to-image";
import { useMemo, useRef, useState } from "react";
import { useSearchParams } from "next/navigation";
import { PosterCanvas } from "@/components/poster-canvas";
import { applyPosterAssetDefaults } from "@/lib/poster-assets";
import {
  heroFrameStyleOptions,
  samplePoster,
  sectionTitleStyleOptions,
  styleOptions,
} from "@/lib/sample-poster";
import { decodePosterPayload, parsePosterDocument } from "@/lib/poster-schema";
import {
  HeroFrameStyle,
  PosterDocument,
  PosterStyle,
  PreviewMode,
  SectionTitleStyle,
} from "@/lib/poster-types";

const initialPoster = applyPosterAssetDefaults(samplePoster);
const initialJson = JSON.stringify(initialPoster, null, 2);

export function PosterStudio() {
  const searchParams = useSearchParams();
  const [jsonOverride, setJsonOverride] = useState<string | null>(null);
  const [posterOverride, setPosterOverride] = useState<PosterDocument | null>(null);
  const [error, setError] = useState<string>("");
  const [isExporting, setIsExporting] = useState(false);
  const [previewMode, setPreviewMode] = useState<PreviewMode>("full");
  const posterRef = useRef<HTMLDivElement>(null);

  const incomingPayload = useMemo(() => {
    const encoded = searchParams.get("data");

    if (!encoded) {
      return {
        poster: null,
        error: "",
      };
    }

    try {
      return {
        poster: decodePosterPayload(encoded),
        error: "",
      };
    } catch (payloadError) {
      return {
        poster: null,
        error:
          payloadError instanceof Error ? payloadError.message : "Khong doc duoc du lieu tu URL.",
      };
    }
  }, [searchParams]);

  const poster = applyPosterAssetDefaults(posterOverride ?? incomingPayload.poster ?? initialPoster);
  const jsonText = jsonOverride ?? JSON.stringify(poster, null, 2);
  const currentError =
    error || (jsonOverride === null && posterOverride === null ? incomingPayload.error : "");

  const stats = {
    fixedBlocks: 5,
    styleCount: styleOptions.length,
  };

  const applyJson = () => {
    try {
      const parsed = applyPosterAssetDefaults(parsePosterDocument(JSON.parse(jsonText)));
      setPosterOverride(parsed);
      setJsonOverride(JSON.stringify(parsed, null, 2));
      setError("");
    } catch (jsonError) {
      setError(jsonError instanceof Error ? jsonError.message : "Invalid JSON format.");
    }
  };

  const setStyle = (style: PosterStyle) => {
    const updated = { ...poster, style };
    setPosterOverride(updated);
    setJsonOverride(JSON.stringify(updated, null, 2));
  };

  const setSectionTitleStyle = (sectionTitleStyle: SectionTitleStyle) => {
    const updated = { ...poster, sectionTitleStyle };
    setPosterOverride(updated);
    setJsonOverride(JSON.stringify(updated, null, 2));
  };

  const setHeroFrameStyle = (heroFrameStyle: HeroFrameStyle) => {
    const updated = { ...poster, heroFrameStyle };
    setPosterOverride(updated);
    setJsonOverride(JSON.stringify(updated, null, 2));
  };

  const downloadPoster = async () => {
    if (!posterRef.current) {
      return;
    }

    try {
      setIsExporting(true);
      const dataUrl = await toPng(posterRef.current, {
        cacheBust: true,
        pixelRatio: 2,
      });
      const link = document.createElement("a");
      link.download = `${poster.brand.companyName.toLowerCase().replace(/\s+/g, "-")}.png`;
      link.href = dataUrl;
      link.click();
    } catch (exportError) {
      setError(exportError instanceof Error ? exportError.message : "Khong the xuat PNG.");
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <main className="studio-shell">
      <section className="studio-panel studio-intro">
        <div>
          <p className="eyebrow">Next.js Poster Generator</p>
          <h1>Tao poster tu JSON voi mau nganh va form mobile ro rang</h1>
          <p className="intro-copy">
            App nay gom 5 khung co dinh: ten cong ty, noi dung cong viec, moi truong lam viec,
            dinh huong phat trien, chuyen nganh tuyen dung. Mau se doi theo nganh va co them che
            do mobile truot hoac tach 4 anh.
          </p>
        </div>
        <div className="intro-actions">
          <button
            className="pill"
            onClick={() => {
              setJsonOverride(initialJson);
              setPosterOverride(initialPoster);
              setError("");
              setPreviewMode("full");
            }}
            type="button"
          >
            Reset sample
          </button>
        </div>
        <div className="intro-actions">
          {styleOptions.map((style) => (
            <button
              className={poster.style === style ? "pill active" : "pill"}
              key={style}
              onClick={() => setStyle(style)}
              type="button"
            >
              Style {style}
            </button>
          ))}
        </div>
        <div className="intro-actions">
          {sectionTitleStyleOptions.map((style) => (
            <button
              className={poster.sectionTitleStyle === style ? "pill active" : "pill"}
              key={style}
              onClick={() => setSectionTitleStyle(style)}
              type="button"
            >
              Tieu de {style}
            </button>
          ))}
        </div>
        <div className="intro-actions">
          {heroFrameStyleOptions.map((style) => (
            <button
              className={poster.heroFrameStyle === style ? "pill active" : "pill"}
              key={style}
              onClick={() => setHeroFrameStyle(style)}
              type="button"
            >
              Hero {style}
            </button>
          ))}
        </div>
        <div className="intro-actions">
          <button
            className={previewMode === "full" ? "pill active" : "pill"}
            onClick={() => setPreviewMode("full")}
            type="button"
          >
            Poster day du
          </button>
          <button
            className={previewMode === "mobile-slide" ? "pill active" : "pill"}
            onClick={() => setPreviewMode("mobile-slide")}
            type="button"
          >
            Mobile truot
          </button>
          <button
            className={previewMode === "mobile-4up" ? "pill active" : "pill"}
            onClick={() => setPreviewMode("mobile-4up")}
            type="button"
          >
            Chia 4 anh
          </button>
        </div>
        <div className="stat-row">
          <article className="stat-card">
            <strong>{stats.fixedBlocks}</strong>
            <span>Fixed blocks</span>
          </article>
          <article className="stat-card">
            <strong>{stats.styleCount}</strong>
            <span>Styles</span>
          </article>
          <article className="stat-card">
            <strong>{poster.industry}</strong>
            <span>Industry color</span>
          </article>
          <article className="stat-card">
            <strong>{poster.sectionTitleStyle ?? "ribbon"}</strong>
            <span>Title style</span>
          </article>
        </div>
      </section>

      <section className="studio-grid">
        <div className="studio-panel editor-panel">
          <div className="panel-header">
            <div>
              <h2>JSON Editor</h2>
              <p>
                Doi `industry` de app tu thay tong mau: automation, construction, electrical,
                electronics, hvac, it, chemistry, other. Ban cung co the doi `sectionTitleStyle`
                va `heroFrameStyle`. Hero image mac dinh se tu lay tu folder `image`.
              </p>
            </div>
            <button className="primary-button" onClick={applyJson} type="button">
              Apply JSON
            </button>
          </div>
          <textarea
            aria-label="Poster JSON"
            className="json-editor"
            onChange={(event) => setJsonOverride(event.target.value)}
            spellCheck={false}
            value={jsonText}
          />
          <div className="helper-row">
            <span>
              Schema chinh: `industry`, `style`, `companySection`, `jobSection`,
              `environmentSection`, `growthSection`, `majorSection`, `sectionTitleStyle`,
              `heroFrameStyle`
            </span>
            {currentError ? <strong className="error-text">{currentError}</strong> : null}
          </div>
        </div>

        <div className="studio-panel preview-panel">
          <div className="panel-header">
            <div>
              <h2>Poster Preview</h2>
              <p>Poster day du cho desktop, hoac chia thanh cac trang lon de doc tren dien thoai.</p>
            </div>
            <button className="primary-button" onClick={downloadPoster} type="button">
              {isExporting ? "Dang xuat..." : "Export PNG"}
            </button>
          </div>
          <div className="preview-scroll">
            <div ref={posterRef}>
              <PosterCanvas poster={poster} previewMode={previewMode} />
            </div>
          </div>
        </div>
      </section>
    </main>
  );
}
